def ensure_question_difficulties():
    def infer_difficulty(question_id):
        if not isinstance(question_id, int):
            return 'Medium'
        if question_id <= 8:
            return 'Easy'
        if question_id <= 17:
            return 'Medium'
        return 'Hard'

    for exam_type, questions in QUESTION_BANK.items():
        for q in questions:
            if 'difficulty' not in q or not q.get('difficulty'):
                q['difficulty'] = infer_difficulty(q.get('id'))


ensure_question_difficulties()



from flask import jsonify

# 模拟用户进度数据 (在实际应用中应存储在数据库中)
# 结构: exam_type -> {completed: set(question_ids), correct: set(question_ids), total_attempts: 0}
USER_PROGRESS = {
    'ap_micro': {'completed': set(), 'correct': set(), 'total_attempts': 0},
    'ap_macro': {'completed': set(), 'correct': set(), 'total_attempts': 0},
    'igcse': {'completed': set(), 'correct': set(), 'total_attempts': 0},
    'a_level': {'completed': set(), 'correct': set(), 'total_attempts': 0},
    'dse': {'completed': set(), 'correct': set(), 'total_attempts': 0}
}

# Redis 连接
redis_client = None
if REDIS_AVAILABLE:
    try:
        redis_url = os.environ.get('REDIS_URL')
        if redis_url:
            redis_client = redis.from_url(redis_url)
        else:
            redis_host = os.environ.get('REDIS_HOST', 'localhost')
            redis_port = int(os.environ.get('REDIS_PORT', 6379))
            redis_password = os.environ.get('REDIS_PASSWORD', None)
            redis_client = redis.Redis(
                host=redis_host,
                port=redis_port,
                password=redis_password,
                decode_responses=True
            )
        redis_client.ping()
        print('Redis connected successfully')
    except Exception as e:
        print(f'Redis connection failed: {e}')
        redis_client = None

# 共享quiz数据存储 (内存作为Redis的备用)
SHARED_QUIZZES = {}

# 存储共享quiz
def save_shared_quiz(quiz_id, quiz_data):
    quiz_data_json = json.dumps(quiz_data)
    if redis_client:
        try:
            redis_client.setex(f'quiz:{quiz_id}', 86400 * 7, quiz_data_json)
            return True
        except Exception as e:
            print(f'Failed to save to Redis: {e}')
    SHARED_QUIZZES[quiz_id] = quiz_data
    return True

# 获取共享quiz
def get_shared_quiz(quiz_id):
    if redis_client:
        try:
            quiz_data_json = redis_client.get(f'quiz:{quiz_id}')
            if quiz_data_json:
                return json.loads(quiz_data_json)
        except Exception as e:
            print(f'Failed to get from Redis: {e}')
    return SHARED_QUIZZES.get(quiz_id)

# 辅助函数：获取用户统计
def get_user_stats():
    total_completed = 0
    total_correct = 0
    
    stats = {}
    
    for exam_type, data in USER_PROGRESS.items():
        completed_count = len(data['completed'])
        correct_count = len(data['correct'])
        accuracy = int((correct_count / completed_count * 100)) if completed_count > 0 else 0
        questions = QUESTION_BANK.get(exam_type, [])
        total_questions = len(questions)
        
        stats[exam_type] = {
            'completed': completed_count,
            'total': total_questions,
            'accuracy': accuracy
        }
        
        total_completed += completed_count
        total_correct += correct_count
    
    overall_accuracy = int((total_correct / total_completed * 100)) if total_completed > 0 else 0
    
    return {
        'overall': {
            'completed': total_completed,
            'accuracy': overall_accuracy
        },
        'by_exam': stats
    }

# 辅助函数：获取章节统计
def get_section_stats(exam_type):
    questions = QUESTION_BANK.get(exam_type, [])
    section_counts = {}
    
    for q in questions:
        section = q.get('section', 'Unknown')
        if section not in section_counts:
            section_counts[section] = 0
        section_counts[section] += 1
    
    return section_counts

# 辅助函数：根据章节和难度筛选题目
def filter_questions(exam_type, section=None, difficulty=None):
    questions = QUESTION_BANK.get(exam_type, [])
    filtered = []
    
    for q in questions:
        if section and q.get('section') != section:
            continue
        if difficulty and q.get('difficulty') != difficulty:
            continue
        filtered.append(q)
    
    return filtered

# 辅助函数：生成随机题目
def generate_random_questions(exam_type, count=10, section=None, difficulty=None):
    import random
    questions = filter_questions(exam_type, section, difficulty)
    random.shuffle(questions)
    return questions[:count]

# 辅助函数：获取下一题ID
def get_next_question_id(exam_type, current_id):
    questions = QUESTION_BANK.get(exam_type, [])
    question_ids = sorted([q['id'] for q in questions])
    
    if not question_ids:
        return None
    
    if current_id is None:
        return question_ids[0]
    
    current_index = question_ids.index(current_id)
    if current_index < len(question_ids) - 1:
        return question_ids[current_index + 1]
    
    return None

# 辅助函数：获取上一题ID
def get_prev_question_id(exam_type, current_id):
    questions = QUESTION_BANK.get(exam_type, [])
    question_ids = sorted([q['id'] for q in questions])
    
    if not question_ids:
        return None
    
    if current_id is None:
        return question_ids[-1]
    
    current_index = question_ids.index(current_id)
    if current_index > 0:
        return question_ids[current_index - 1]
    
    return None

# 辅助函数：获取题目总数
def get_total_questions(exam_type):
    return len(QUESTION_BANK.get(exam_type, []))

# 辅助函数：获取已完成题目数
def get_completed_questions(exam_type):
    return len(USER_PROGRESS.get(exam_type, {}).get('completed', set()))

# 辅助函数：获取正确率
def get_accuracy(exam_type):
    data = USER_PROGRESS.get(exam_type, {})
    completed = len(data.get('completed', set()))
    correct = len(data.get('correct', set()))
    return int((correct / completed * 100)) if completed > 0 else 0

# 辅助函数：获取章节列表
def get_sections(exam_type):
    questions = QUESTION_BANK.get(exam_type, [])
    sections = set()
    
    for q in questions:
        section = q.get('section', 'Unknown')
        sections.add(section)
    
    return sorted(sections)

# 辅助函数：获取难度级别
def get_difficulties(exam_type):
    questions = QUESTION_BANK.get(exam_type, [])
    difficulties = set()
    
    for q in questions:
        difficulty = q.get('difficulty', 'Medium')
        difficulties.add(difficulty)
    
    return sorted(difficulties)

# 辅助函数：获取题目
def get_question(exam_type, question_id):
    questions = QUESTION_BANK.get(exam_type, [])
    for q in questions:
        if q['id'] == question_id:
            return q
    return None

# 辅助函数：检查答案
def check_answer(exam_type, question_id, answer):
    question = get_question(exam_type, question_id)
    if not question:
        return False
    
    return question.get('answer') == answer

# 辅助函数：更新用户进度
def update_user_progress(exam_type, question_id, is_correct):
    data = USER_PROGRESS.get(exam_type, {})
    data['completed'].add(question_id)
    if is_correct:
        data['correct'].add(question_id)
    data['total_attempts'] = data.get('total_attempts', 0) + 1

