# 路由：开始练习
@app.route('/practice/<exam_type>/<int:question_id>')
def practice(exam_type, question_id):
    refresh_translations_if_needed()
    if exam_type not in QUESTION_BANK:
        return redirect(url_for('select_exam'))
    
    question = get_question(exam_type, question_id)
    if not question:
        return redirect(url_for('select_section', exam_type=exam_type))
    
    next_id = get_next_question_id(exam_type, question_id)
    prev_id = get_prev_question_id(exam_type, question_id)
    
    next_url = url_for('practice', exam_type=exam_type, question_id=next_id) if next_id else None
    prev_url = url_for('practice', exam_type=exam_type, question_id=prev_id) if prev_id else None
    
    return render_template('practice.html', 
                           exam_type=exam_type, 
                           question=question, 
                           next_url=next_url, 
                           prev_url=prev_url)

# 路由：提交答案
@app.route('/submit-answer', methods=['POST'])
def submit_answer():
    refresh_translations_if_needed()
    data = request.json
    exam_type = data.get('exam_type')
    question_id = data.get('question_id')
    answer = data.get('answer')
    
    if not exam_type or not question_id or not answer:
        return jsonify({'error': 'Missing required fields'})
    
    is_correct = check_answer(exam_type, question_id, answer)
    update_user_progress(exam_type, question_id, is_correct)
    
    question = get_question(exam_type, question_id)
    if not question:
        return jsonify({'error': 'Question not found'})
    
    return jsonify({
        'is_correct': is_correct,
        'explanation': question.get('explanation', ''),
        'correct_answer': question.get('answer', '')
    })

# 路由：生成Quiz
@app.route('/generate-quiz/<exam_type>')
def generate_quiz(exam_type):
    refresh_translations_if_needed()
    if exam_type not in QUESTION_BANK:
        return redirect(url_for('select_exam'))
    
    sections_param = request.args.get('sections')
    section = request.args.get('section')
    count = request.args.get('count', type=int, default=10)
    
    # 获取符合条件的题目
    questions_all = QUESTION_BANK[exam_type]
    selected_questions = []
    
    if sections_param:
        try:
            selected_sections = json.loads(sections_param)
            # 按章节分组
            section_questions = {}
            for s in selected_sections:
                section_questions[s] = [q for q in questions_all if q.get('section') == s]
            
            # 计算每个章节应该选多少题
            num_sections = len(selected_sections)
            questions_per_section = count // num_sections
            remaining_questions = count % num_sections
            
            # 从每个章节均匀随机挑选题目
            import random
            for i, s in enumerate(selected_sections):
                q_list = section_questions[s]
                # 第一个 remaining_questions 个章节多拿1题
                num_to_take = questions_per_section + (1 if i < remaining_questions else 0)
                # 确保不超过该章节的题目数量
                num_to_take = min(num_to_take, len(q_list))
                # 随机打乱并选择
                random.shuffle(q_list)
                selected_questions.extend(q_list[:num_to_take])
            
            # 最后打乱所有选中的题目顺序
            random.shuffle(selected_questions)
            
            # 如果题数不够，用第一个章节的题补足
            if len(selected_questions) < count and selected_sections:
                first_section = selected_sections[0]
                first_section_questions = [q for q in questions_all if q.get('section') == first_section]
                random.shuffle(first_section_questions)
                for q in first_section_questions:
                    if len(selected_questions) >= count:
                        break
                    if q not in selected_questions:
                        selected_questions.append(q)
            
            # 确保题数不超过要求
            selected_questions = selected_questions[:count]
            
        except (json.JSONDecodeError, Exception):
            # 如果解析失败，回退到单个章节或所有题目的模式
            questions = questions_all
            if section:
                questions = [q for q in questions if q.get('section') == section]
            import random
            random.shuffle(questions)
            selected_questions = questions[:count]
    else:
        # 单个章节或所有题目的模式
        questions = questions_all
        if section:
            questions = [q for q in questions if q.get('section') == section]
        import random
        random.shuffle(questions)
        selected_questions = questions[:count]
    
    # 保存到session
    session['quiz_questions'] = [q['id'] for q in selected_questions]
    session['quiz_current'] = 0
    session['quiz_answers'] = {}
    session['quiz_exam_type'] = exam_type
    
    if selected_questions:
        first_question_id = selected_questions[0]['id']
        return redirect(url_for('quiz', exam_type=exam_type, question_id=first_question_id))
    else:
        return redirect(url_for('select_section', exam_type=exam_type))

# 路由：Quiz题目
@app.route('/quiz/<exam_type>/<int:question_id>')
def quiz(exam_type, question_id):
    refresh_translations_if_needed()
    if exam_type not in QUESTION_BANK:
        return redirect(url_for('select_exam'))
    
    # 检查session中的quiz数据
    if 'quiz_questions' not in session or 'quiz_current' not in session:
        return redirect(url_for('select_section', exam_type=exam_type))
    
    quiz_questions = session['quiz_questions']
    quiz_current = session['quiz_current']
    
    # 检查当前题目是否在quiz中
    if question_id not in quiz_questions:
        return redirect(url_for('select_section', exam_type=exam_type))
    
    # 更新当前位置
    session['quiz_current'] = quiz_questions.index(question_id)
    
    question = get_question(exam_type, question_id)
    if not question:
        return redirect(url_for('select_section', exam_type=exam_type))
    
    # 获取下一题
    next_index = quiz_current + 1
    if next_index < len(quiz_questions):
        next_id = quiz_questions[next_index]
        next_url = url_for('quiz', exam_type=exam_type, question_id=next_id)
    else:
        next_url = url_for('quiz_result')
    
    return render_template('quiz.html', 
                           exam_type=exam_type, 
                           question=question, 
                           next_url=next_url, 
                           current=quiz_current + 1, 
                           total=len(quiz_questions))

# 路由：保存Quiz答案
@app.route('/save-quiz-answer', methods=['POST'])
def save_quiz_answer():
    refresh_translations_if_needed()
    data = request.json
    question_id = data.get('question_id')
    answer = data.get('answer')
    
    if not question_id or not answer:
        return jsonify({'error': 'Missing required fields'})
    
    # 保存答案到session
    if 'quiz_answers' not in session:
        session['quiz_answers'] = {}
    session['quiz_answers'][str(question_id)] = answer
    
    # 检查答案是否正确并更新用户进度
    exam_type = session.get('quiz_exam_type')
    if exam_type:
        is_correct = check_answer(exam_type, question_id, answer)
        update_user_progress(exam_type, question_id, is_correct)
        
        # 如果答错了，添加到错题本
        if not is_correct:
            question = get_question(exam_type, question_id)
            if question:
                if 'wrong_questions' not in session:
                    session['wrong_questions'] = []
                # 检查是否已经在错题本中
                if not any(q.get('id') == question_id and q.get('exam_type') == exam_type for q in session['wrong_questions']):
                    session['wrong_questions'].append({
                        'exam_type': exam_type,
                        'id': question_id,
                        'question': question['question'],
                        'options': question['options'],
                        'answer': question['answer'],
                        'explanation': question['explanation'],
                        'section': question.get('section'),
                        'difficulty': question.get('difficulty')
                    })
    
    return jsonify({'success': True})

# 路由：Quiz结果
@app.route('/quiz-result')
def quiz_result():
    refresh_translations_if_needed()
    if 'quiz_questions' not in session or 'quiz_answers' not in session:
        return redirect(url_for('select_exam'))
    
    exam_type = session.get('quiz_exam_type')
    quiz_questions = session['quiz_questions']
    quiz_answers = session['quiz_answers']
    
    # 计算得分
    correct_count = 0
    total_count = len(quiz_questions)
    results = []
    
    for question_id in quiz_questions:
        question = get_question(exam_type, question_id)
        if not question:
            continue
        
        user_answer = quiz_answers.get(str(question_id))
        is_correct = user_answer == question.get('answer')
        if is_correct:
            correct_count += 1
        
        results.append({
            'question': question,
            'user_answer': user_answer,
            'is_correct': is_correct
        })
    
    score = int((correct_count / total_count) * 100) if total_count > 0 else 0
    
    # 清除session中的quiz数据
    session.pop('quiz_questions', None)
    session.pop('quiz_current', None)
    session.pop('quiz_answers', None)
    session.pop('quiz_exam_type', None)
    
    return render_template('quiz_result.html', 
                           exam_type=exam_type, 
                           results=results, 
                           score=score, 
                           correct_count=correct_count, 
                           total_count=total_count)

# 路由：创建共享Quiz
@app.route('/create-shared-quiz', methods=['POST'])
def create_shared_quiz():
    refresh_translations_if_needed()
    data = request.json
    exam_type = data.get('exam_type')
    sections = data.get('sections')
    count = data.get('count', 10)
    
    if not exam_type:
        return jsonify({'error': 'Missing exam type'})
    
    # 生成Quiz题目
    questions_all = QUESTION_BANK[exam_type]
    selected_questions = []
    
    if sections:
        try:
            # 按章节分组
            section_questions = {}
            for s in sections:
                section_questions[s] = [q for q in questions_all if q.get('section') == s]
            
            # 计算每个章节应该选多少题
            num_sections = len(sections)
            questions_per_section = count // num_sections
            remaining_questions = count % num_sections
            
            # 从每个章节均匀随机挑选题目
            import random
            for i, s in enumerate(sections):
                q_list = section_questions[s]
                # 第一个 remaining_questions 个章节多拿1题
                num_to_take = questions_per_section + (1 if i < remaining_questions else 0)
                # 确保不超过该章节的题目数量
                num_to_take = min(num_to_take, len(q_list))
                # 随机打乱并选择
                random.shuffle(q_list)
                selected_questions.extend(q_list[:num_to_take])
            
            # 最后打乱所有选中的题目顺序
            random.shuffle(selected_questions)
            
            # 如果题数不够，用第一个章节的题补足
            if len(selected_questions) < count and sections:
                first_section = sections[0]
                first_section_questions = [q for q in questions_all if q.get('section') == first_section]
                random.shuffle(first_section_questions)
                for q in first_section_questions:
                    if len(selected_questions) >= count:
                        break
                    if q not in selected_questions:
                        selected_questions.append(q)
            
            # 确保题数不超过要求
            selected_questions = selected_questions[:count]
            
        except Exception:
            # 如果解析失败，回退到所有题目的模式
            import random
            random.shuffle(questions_all)
            selected_questions = questions_all[:count]
    else:
        # 从所有题目中随机选择
        import random
        random.shuffle(questions_all)
        selected_questions = questions_all[:count]
    
    # 生成唯一ID
    quiz_id = str(uuid.uuid4())
    
    # 保存共享Quiz
    quiz_data = {
        'exam_type': exam_type,
        'questions': [q['id'] for q in selected_questions],
        'created_at': time.time(),
        'answers': {}
    }
    
    save_shared_quiz(quiz_id, quiz_data)
    
    # 生成分享链接
    share_url = url_for('shared_quiz', quiz_id=quiz_id, _external=True)
    
    return jsonify({'quiz_id': quiz_id, 'share_url': share_url})

